mapper.select:
select d.id,d.name,d.category_id,d.image,d.price,d.description,d.status,d.update_time,category.name as category_name
    from dish as d
    left join category on d.category_id=category.id


           d.name like concat('%',#{name},'%')


           and d.category_id=#{categoryId}


            and d.status=#{status}
